import { extractString } from '../../utils/extract.js';
import { handleError } from '../error.js';
export const createServerPreUploadItemActionRouteHandler = (group) => async ({ req, res, next, localize, ctx }) => {
    if (!group.preUploadActionHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const key = extractString(req.headers['sonolus-upload-key']);
    if (key === undefined) {
        res.status(400).end();
        return;
    }
    const response = await group.preUploadActionHandler({ ...ctx, itemName, key });
    if (handleError(response, res, localize))
        return;
    next();
};
